import { useState } from "react";
import { Navigate, useNavigate, Link } from "react-router-dom";
import { api, setAuthToken, isSignupComplete } from "../api";
import "../styles/auth.css";

export default function Login() {
  const navigate = useNavigate();
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  if (!isSignupComplete()) {
    return <Navigate to="/signup" replace />;
  }

  const handleLogin = async (e) => {
    e.preventDefault();

    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailPattern.test(email)) {
      setError("Please enter a valid email address.");
      return;
    }

    try {
      setError("");
      setLoading(true);
      const res = await api.post("/auth/login/", { username, email, password });
      setAuthToken(res.data.token);
      setLoading(false);
      navigate("/search");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Login failed. Please try again.");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-background">
        <div className="blob blob1"></div>
        <div className="blob blob2"></div>
        <div className="blob blob3"></div>
      </div>

      <div className="auth-card">
        <div className="auth-header">
          <h1>Welcome Back</h1>
          <p>Sign in to access your medicines</p>
        </div>

        <form onSubmit={handleLogin} className="auth-form">
          <div className="form-group">
            <label htmlFor="username">Username</label>
            <input
              id="username"
              type="text"
              placeholder="Enter your username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              placeholder="Enter your registered email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
              placeholder="Enter your password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
          </div>

          {error && <div className="error-box">{error}</div>}

          <button type="submit" className="btn-login" disabled={loading}>
            {loading ? "Signing in..." : "Sign In"}
          </button>
        </form>

        <div className="auth-footer">
          <p>Don't have an account? <Link to="/signup" className="auth-link">Sign Up</Link></p>
        </div>
      </div>

      <div className="auth-features">
        <div className="feature">
          <div className="feature-icon">🏥</div>
          <h3>Easy Access</h3>
          <p>Quick and secure login</p>
        </div>
        <div className="feature">
          <div className="feature-icon">💊</div>
          <h3>Browse Medicines</h3>
          <p>Find quality medicines</p>
        </div>
        <div className="feature">
          <div className="feature-icon">🛒</div>
          <h3>Fast Checkout</h3>
          <p>Quick order placement</p>
        </div>
      </div>
    </div>
  );
}
